+    #[test]
+    fn corrupt_decoded_output_maps_to_recoverable_insufficient_symbols() {
+        let mapped = RaptorQDecoder::map_decode_error(
+            crate::codec::decoder::DecodeError::CorruptDecodedOutput {
+                esi: 91,
+                byte_index: 7,
+                expected: 0xAA,
+                actual: 0x55,
+            },
+            80,
+            82,
+        );
+
+        assert_eq!(
+            mapped,
+            DecodeError::InsufficientSymbols {
+                received: 80,
+                needed: 82,
+            }
+        );
+    }
